"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[2093],{7475(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>s,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"stoicism/marcus-aurelius/meditations/meditations-book-1","title":"Meditations \u2014 Book 1","description":"Book 1","source":"@site/docs/stoicism/marcus-aurelius/meditations/meditations-book-1.md","sourceDirName":"stoicism/marcus-aurelius/meditations","slug":"/stoicism/marcus-aurelius/meditations/meditations-book-1","permalink":"/justinus/docs/stoicism/marcus-aurelius/meditations/meditations-book-1","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"sidebar_position":1,"title":"Meditations \u2014 Book 1","sidebar_label":"Book 1"},"sidebar":"philosophersSidebar","previous":{"title":"Marcus Aurelius","permalink":"/justinus/docs/stoicism/marcus-aurelius/"},"next":{"title":"Book 2","permalink":"/justinus/docs/stoicism/marcus-aurelius/meditations/meditations-book-2"}}');var i=o(4848),a=o(8453);const s={sidebar_position:1,title:"Meditations \u2014 Book 1",sidebar_label:"Book 1"},r="Meditations",h={},d=[{value:"Book 1",id:"book-1",level:2},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Table",id:"table",level:2},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",p:"p",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...(0,a.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)("div",{style:{textAlign:"center"},children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"meditations",children:"Meditations"})}),(0,i.jsx)(t.h2,{id:"book-1",children:"Book 1"})]}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.p,{children:"Book 1 is unlike every other book \u2014 no philosophy, no aphorisms, no meditations on death. It's a pure act of gratitude, a man cataloguing what he owes to the people who shaped him."}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The structure"}),' \u2014 Eighteen entries, each beginning "From [person] I learned..." Moving from family to tutors to teachers to his adoptive father Antoninus Pius to the gods themselves.']}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"What he learned from family"})," \u2014 From his grandfather: good morals and temper. From his father's memory: modesty and manliness. From his mother: piety, generosity, simplicity, abstinence even from evil ",(0,i.jsx)(t.em,{children:"thoughts"}),". From his great-grandfather: get private tutors, not public schools, and spend liberally on education."]}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"From his teachers"})," \u2014 A long procession of specific debts. From Rusticus: that his character needed improvement; to avoid sophistry and showing off; to read carefully; to reconcile quickly with those who've wronged you. It was Rusticus who introduced him to Epictetus. From Apollonius: steadiness of purpose, looking only to reason, being the same whether in pain or grief or illness. From Sextus: benevolence, living according to nature, tolerating ignorant people, never showing anger. From Fronto: what envy and hypocrisy look like in those who hold power."]}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The portrait of Antoninus Pius"})," \u2014 The longest and most loving entry in the book. Marcus's adoptive father is described with extraordinary specificity and admiration: mildness combined with firm resolve, no vanity about honors, patient listening, careful deliberation that never stopped at first appearances, no superstition, no flattery of the crowd, modest in dress and food and habits, generous to true philosophers without being taken in by false ones. The line that stands out: ",(0,i.jsx)(t.em,{children:"he was able both to abstain from and to enjoy those things which many are too weak to abstain from."})," Marcus clearly saw in Antoninus the person he was trying to become."]}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The thanksgiving to the gods"})," \u2014 The final entry is the most personal thing in the entire twelve books. He thanks the gods for good grandparents, parents, teachers, friends. For never being pushed into an offense he might otherwise have committed. For not being raised by his grandfather's concubine. For preserving his youth and not rushing into sex before the right time. For having a ruler who removed his pride and showed him you could live in a palace like a private person. For his children not being stupid or deformed. For not making ",(0,i.jsx)(t.em,{children:"too much"})," progress in rhetoric and poetry, which might have consumed him entirely. For knowing Apollonius, Rusticus, and Maximus. For his wife being obedient, affectionate, and simple. For never being unable to help someone who needed it. For remedies shown to him in dreams. For not falling into the hands of a sophist when he turned to philosophy."]}),(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The closing line"}),' \u2014 "Among the Quadi at the Granua." Written on campaign, on the Danube frontier, just like the close of Book 2. The most private book in the collection, written in a military camp far from Rome.']}),(0,i.jsx)(t.p,{children:"What makes Book 1 remarkable is its tone \u2014 warm, specific, humble. Every other book is Marcus instructing himself. This one is Marcus saying thank you."})]}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Table"}),(0,i.jsx)(t.h2,{id:"table",children:"Table"}),(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Name"}),(0,i.jsx)(t.th,{children:"Relation"}),(0,i.jsx)(t.th,{children:"Quality"})]})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Verus"}),(0,i.jsx)(t.td,{children:"grandfather"}),(0,i.jsx)(t.td,{children:"decency, mild temper"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.em,{children:"unknown"})}),(0,i.jsx)(t.td,{children:"father (biological)"}),(0,i.jsx)(t.td,{children:"integrity, manliness"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.em,{children:"unknown"})}),(0,i.jsx)(t.td,{children:"mother"}),(0,i.jsx)(t.td,{children:"piety, generosity, virtuous thoughts & actions, simplicity of living"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.em,{children:"unknown"})}),(0,i.jsx)(t.td,{children:"great-grandfather"}),(0,i.jsx)(t.td,{children:"value education (look more into this: line 4)"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.em,{children:"unknown"})}),(0,i.jsx)(t.td,{children:"tutor"}),(0,i.jsx)(t.td,{children:"impartiality at sports events, tolerate pain, feel few needs, work with hands, mind own business, no gossip"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Diognetus"}),(0,i.jsx)(t.td,{children:"teacher"}),(0,i.jsx)(t.td,{children:"avoid trivial preoccupations, skepticism of superstition and miracle-workers, endure free speech, love of philosophy, simple living"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Rusticus"}),(0,i.jsx)(t.td,{children:"teacher / Stoic senator"}),(0,i.jsx)(t.td,{children:"self-improvement over sophistry and display, simplicity in communication, easy reconciliation, careful reading, introduced Epictetus"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Apollonius"}),(0,i.jsx)(t.td,{children:"teacher / Stoic philosopher"}),(0,i.jsx)(t.td,{children:"freedom of will, undeviating steadiness of purpose, pure reason above all else, equanimity in pain and loss, resolute yet yielding"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Sextus"}),(0,i.jsx)(t.td,{children:"teacher / philosopher"}),(0,i.jsx)(t.td,{children:"benevolent disposition, natural living, gravity without affectation, care for friends, tolerance of the ignorant, free from passion yet affectionate"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Alexander"}),(0,i.jsx)(t.td,{children:"teacher / grammarian"}),(0,i.jsx)(t.td,{children:"gentle correction without reproach, redirect to correct usage naturally rather than criticizing the person"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Fronto"}),(0,i.jsx)(t.td,{children:"teacher / rhetorician"}),(0,i.jsx)(t.td,{children:"awareness of envy, duplicity, and hypocrisy in those with power; that patricians are often deficient in paternal affection"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Alexander"}),(0,i.jsx)(t.td,{children:"teacher / Platonic philosopher"}),(0,i.jsx)(t.td,{children:"not using busyness as an excuse, not neglecting relational duties by claiming urgent occupations"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Catulus"}),(0,i.jsx)(t.td,{children:"teacher / philosopher"}),(0,i.jsx)(t.td,{children:"receptiveness to a friend's criticism even without cause, speaking well of teachers, true love of children"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Severus"}),(0,i.jsx)(t.td,{children:"brother"}),(0,i.jsx)(t.td,{children:"love of kin, truth, and justice; republican ideals (equal law, equal rights, free speech); consistency in philosophy; generosity; transparency of opinion"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Maximus"}),(0,i.jsx)(t.td,{children:"friend / mentor"}),(0,i.jsx)(t.td,{children:"self-mastery, cheerfulness in all circumstances including illness, sweetness with dignity, integrity, beneficence, forgiveness, agreeable humor"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.em,{children:"unknown"})}),(0,i.jsx)(t.td,{children:"adoptive father (emperor)"}),(0,i.jsx)(t.td,{children:"mildness with firm resolution, no vainglory, love of labour, attentiveness to counsel, firmness in giving deserts, frugality, sobriety, honor for philosophers"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"The gods"}),(0,i.jsx)(t.td,{children:"divine"}),(0,i.jsx)(t.td,{children:"good family, teachers, and companions; protection from moral failure; life circumstances favorable to philosophy"})]})]})]})]}),"\n",(0,i.jsxs)(o,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(t.h2,{id:"text",children:"Text"}),(0,i.jsx)(t.p,{children:"From my grandfather Verus I learned good morals and the government of my temper."}),(0,i.jsx)(t.p,{children:"From the reputation and remembrance of my father, modesty and a manly character."}),(0,i.jsx)(t.p,{children:"From my mother, piety and beneficence, and abstinence, not only from evil deeds, but even from evil thoughts; and further, simplicity in my way of living, far removed from the habits of the rich."}),(0,i.jsx)(t.p,{children:"From my great-grandfather, not to have frequented public schools, and to have had good teachers at home, and to know that on such things a man should spend liberally."}),(0,i.jsx)(t.p,{children:"From my governor, to be neither of the green nor of the blue party at the games in the Circus, nor a partizan either of the Parmularius or the Scutarius at the gladiators' fights; from him too I learned endurance of labour, and to want little, and to work with my own hands, and not to meddle with other people's affairs, and not to be ready to listen to slander."}),(0,i.jsx)(t.p,{children:"From Diognetus, not to busy myself about trifling things, and not to give credit to what was said by miracle-workers and jugglers about incantations and the driving away of daemons and such things; and not to breed quails for fighting, nor to give myself up passionately to such things; and to endure freedom of speech; and to have become intimate with philosophy; and to have been a hearer, first of Bacchius, then of Tandasis and Marcianus; and to have written dialogues in my youth; and to have desired a plank bed and skin, and whatever else of the kind belongs to the Grecian discipline."}),(0,i.jsx)(t.p,{children:"From Rusticus I received the impression that my character required improvement and discipline; and from him I learned not to be led astray to sophistic emulation, nor to writing on speculative matters, nor to delivering little hortatory orations, nor to showing myself off as a man who practises much discipline, or does benevolent acts in order to make a display; and to abstain from rhetoric, and poetry, and fine writing; and not to walk about in the house in my outdoor dress, nor to do other things of the kind; and to write my letters with simplicity, like the letter which Rusticus wrote from Sinuessa to my mother; and with respect to those who have offended me by words, or done me wrong, to be easily disposed to be pacified and reconciled, as soon as they have shown a readiness to be reconciled; and to read carefully, and not to be satisfied with a superficial understanding of a book; nor hastily to give my assent to those who talk overmuch; and I am indebted to him for being acquainted with the discourses of Epictetus, which he communicated to me out of his own collection."}),(0,i.jsx)(t.p,{children:"From Apollonius I learned freedom of will and undeviating steadiness of purpose; and to look to nothing else, not even for a moment, except to reason; and to be always the same, in sharp pains, on the occasion of the loss of a child, and in long illness; and to see clearly in a living example that the same man can be both most resolute and yielding, and not peevish in giving his instruction; and to have had before my eyes a man who clearly considered his experience and his skill in expounding philosophical principles as the smallest of his merits; and from him I learned how to receive from friends what are esteemed favours, without being either humbled by them or letting them pass unnoticed."}),(0,i.jsx)(t.p,{children:"From Sextus, a benevolent disposition, and the example of a family governed in a fatherly manner, and the idea of living conformably to nature; and gravity without affectation, and to look carefully after the interests of friends, and to tolerate ignorant persons, and those who form opinions without consideration: he had the power of readily accommodating himself to all, so that intercourse with him was more agreeable than any flattery; and at the same time he was most highly venerated by those who associated with him: and he had the faculty both of discovering and ordering, in an intelligent and methodical way, the principles necessary for life; and he never showed anger or any other passion, but was entirely free from passion, and also most affectionate; and he could express approbation without noisy display, and he possessed much knowledge without ostentation."}),(0,i.jsx)(t.p,{children:"From Alexander the grammarian, to refrain from fault-finding, and not in a reproachful way to chide those who uttered any barbarous or solecistic or strange-sounding expression; but dexterously to introduce the very expression which ought to have been used, and in the way of answer or giving confirmation, or joining in an inquiry about the thing itself, not about the word, or by some other fit suggestion."}),(0,i.jsx)(t.p,{children:"From Fronto I learned to observe what envy, and duplicity, and hypocrisy are in a tyrant, and that generally those among us who are called Patricians are rather deficient in paternal affection."}),(0,i.jsx)(t.p,{children:"From Alexander the Platonic, not frequently nor without necessity to say to any one, or to write in a letter, that I have no leisure; nor continually to excuse the neglect of duties required by our relation to those with whom we live, by alleging urgent occupations."}),(0,i.jsx)(t.p,{children:"From Catulus, not to be indifferent when a friend finds fault, even if he should find fault without reason, but to try to restore him to his usual disposition; and to be ready to speak well of teachers, as it is reported of Domitius and Athenodotus; and to love my children truly."}),(0,i.jsx)(t.p,{children:"From my brother Severus, to love my kin, and to love truth, and to love justice; and through him I learned to know Thrasea, Helvidius, Cato, Dion, Brutus; and from him I received the idea of a polity in which there is the same law for all, a polity administered with regard to equal rights and equal freedom of speech, and the idea of a kingly government which respects most of all the freedom of the governed; I learned from him also consistency and undeviating steadiness in my regard for philosophy; and a disposition to do good, and to give to others readily, and to cherish good hopes, and to believe that I am loved by my friends; and in him I observed no concealment of his opinions with respect to those whom he condemned, and that his friends had no need to conjecture what he wished or did not wish, but it was quite plain."}),(0,i.jsx)(t.p,{children:"From Maximus I learned self-government, and not to be led aside by anything; and cheerfulness in all circumstances, as well as in illness; and a just admixture in the moral character of sweetness and dignity, and to do what was set before me without complaining. I observed that everybody believed that he thought as he spoke, and that in all that he did he never had any bad intention; and he never showed amazement and surprise, and was never in a hurry, and never put off doing a thing, nor was perplexed nor dejected, nor did he ever laugh to disguise his vexation, nor, on the other hand, was he ever passionate or suspicious. He was accustomed to do acts of beneficence, and was ready to forgive, and was free from all falsehood; and he presented the appearance of a man who could not be diverted from right rather than of a man who had been improved. I observed, too, that no man could ever think that he was despised by Maximus, or ever venture to think himself a better man. He had also the art of being humorous in an agreeable way."}),(0,i.jsx)(t.p,{children:"In my father I observed mildness of temper, and unchangeable resolution in the things which he had determined after due deliberation; and no vainglory in those things which men call honours; and a love of labour and perseverance; and a readiness to listen to those who had anything to propose for the common weal; and undeviating firmness in giving to every man according to his deserts; and a knowledge derived from experience of the occasions for vigorous action and for remission. And I observed that he had overcome all passion for boys; and he considered himself no more than any other citizen; and he released his friends from all obligation to sup with him or to attend him of necessity when he went abroad, and those who had failed to accompany him, by reason of any urgent circumstances, always found him the same. I observed too his habit of careful inquiry in all matters of deliberation, and his persistency, and that he never stopped his investigation through being satisfied with appearances which first present themselves; and that his disposition was to keep his friends, and not to be soon tired of them, nor yet to be extravagant in his affection; and to be satisfied on all occasions, and cheerful; and to foresee things a long way off, and to provide for the smallest without display; and to check immediately popular applause and all flattery; and to be ever watchful over the things which were necessary for the administration of the empire, and to be a good manager of the expenditure, and patiently to endure the blame which he got for such conduct; and he was neither superstitious with respect to the gods, nor did he court men by gifts or by trying to please them, or by flattering the populace; but he showed sobriety in all things and firmness, and never any mean thoughts or action, nor love of novelty. And the things which conduce in any way to the commodity of life, and of which fortune gives an abundant supply, he used without arrogance and without excusing himself; so that when he had them, he enjoyed them without affectation, and when he had them not, he did not want them. No one could ever say of him that he was either a sophist or a home-bred flippant slave or a pedant; but every one acknowledged him to be a man ripe, perfect, above flattery, able to manage his own and other men's affairs. Besides this, he honoured those who were true philosophers, and he did not reproach those who pretended to be philosophers, nor yet was he easily led by them. He was also easy in conversation, and he made himself agreeable without any offensive affectation. He took a reasonable care of his body's health, not as one who was greatly attached to life, nor out of regard to personal appearance, nor yet in a careless way, but so that, through his own attention, he very seldom stood in need of the physician's art or of medicine or external applications. He was most ready to give way without envy to those who possessed any particular faculty, such as that of eloquence or knowledge of the law or of morals, or of anything else; and he gave them his help, that each might enjoy reputation according to his deserts; and he always acted conformably to the institutions of his country, without showing any affectation of doing so. Further, he was not fond of change nor unsteady, but he loved to stay in the same places, and to employ himself about the same things; and after his paroxysms of headache he came immediately fresh and vigorous to his usual occupations. His secrets were not but very few and very rare, and these only about public matters; and he showed prudence and economy in the exhibition of the public spectacles and the construction of public buildings, his donations to the people, and in such things, for he was a man who looked to what ought to be done, not to the reputation which is got by a man's acts. He did not take the bath at unseasonable hours; he was not fond of building houses, nor curious about what he ate, nor about the texture and colour of his clothes, nor about the beauty of his slaves. His dress came from Lorium, his villa on the coast, and from Lanuvium generally. We know how he behaved to the toll-collector at Tusculum who asked his pardon; and such was all his behaviour. There was in him nothing harsh, nor implacable, nor violent, nor, as one may say, anything carried to the sweating point; but he examined all things severally, as if he had abundance of time, and without confusion, in an orderly way, vigorously and consistently. And that might be applied to him which is recorded of Socrates, that he was able both to abstain from, and to enjoy, those things which many are too weak to abstain from, and cannot enjoy without excess. But to be strong enough both to bear the one and to be sober in the other is the mark of a man who has a perfect and invincible soul, such as he showed in the illness of Maximus."}),(0,i.jsx)(t.p,{children:"To the gods I am indebted for having good grandfathers, good parents, a good sister, good teachers, good associates, good kinsmen and friends, nearly everything good. Further, I owe it to the gods that I was not hurried into any offence against any of them, though I had a disposition which, if opportunity had offered, might have led me to do something of this kind; but, through their favour, there never was such a concurrence of circumstances as put me to the trial. Further, I am thankful to the gods that I was not longer brought up with my grandfather's concubine, and that I preserved the flower of my youth, and that I did not make proof of my virility before the proper season, but even deferred the time; that I was subjected to a ruler and a father who was able to take away all pride from me, and to bring me to the knowledge that it is possible for a man to live in a palace without wanting either guards or embroidered dresses, or torches and statues, and such-like show; but that it is in such a man's power to bring himself very near to the fashion of a private person, without being for this reason either meaner in thought, or more remiss in action, with respect to the things which must be done for the public interest in a manner that befits a ruler. I thank the gods for giving me such a brother, who was able by his moral character to rouse me to vigilance over myself, and who, at the same time, pleased me by his respect and affection; that my children have not been stupid nor deformed in body; that I did not make more proficiency in rhetoric, poetry, and the other studies, in which I should perhaps have been completely engaged, if I had seen that I was making progress in them; that I made haste to place those who brought me up in the station of honour, which they seemed to desire, without putting them off with hope of my doing it some time after, because they were then still young; that I knew Apollonius, Rusticus, Maximus; that I received clear and frequent impressions about living according to nature, and what kind of a life that is, so that, so far as depended on the gods, and their gifts, and help, and inspirations, nothing hindered me from forthwith living according to nature, though I still fall short of it through my own fault, and through not observing the admonitions of the gods, and, I may almost say, their direct instructions; that my body has held out so long in such a kind of life; that I never touched either Benedicta or Theodotus, and that, after having fallen into amatory passions, I was cured; and, though I was often out of humour with Rusticus, I never did anything of which I had occasion to repent; that, though it was my mother's fate to die young, she spent the last years of her life with me; that, whenever I wished to help any man in his need, or on any other occasion, I was never told that I had not the means of doing it; and that to myself the same necessity never happened, to receive anything from another; that I have such a wife, so obedient, and so affectionate, and so simple; that I had abundance of good masters for my children; and that remedies have been shown to me by dreams, both others, and against bloodspitting and giddiness...; and that, when I had an inclination to philosophy, I did not fall into the hands of any sophist, and that I did not waste my time on writers of histories, or in the resolution of syllogisms, or occupy myself about the investigation of appearances in the heavens; for all these things require the help of the gods and fortune."}),(0,i.jsx)(t.p,{children:"Among the Quadi at the Granua."})]})]})}function c(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>s,x:()=>r});var n=o(6540);const i={},a=n.createContext(i);function s(e){const t=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);